package cl.duoc.vetcontrol.agenda.controller;
import cl.duoc.vetcontrol.agenda.dto.CitaRequest; import cl.duoc.vetcontrol.agenda.model.Cita; import cl.duoc.vetcontrol.agenda.service.CitaService; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.time.LocalDate; import java.util.List;
@RestController @RequestMapping("/api/v1/citas")
public class CitaController { private final CitaService service; public CitaController(CitaService service){this.service=service;} @GetMapping public ResponseEntity<List<Cita>> all(){return ResponseEntity.ok(service.findAll());} @GetMapping("/{id}") public ResponseEntity<Cita> one(@PathVariable Long id){return ResponseEntity.ok(service.findById(id));} @GetMapping("/fecha/{fecha}") public ResponseEntity<List<Cita>> byFecha(@PathVariable LocalDate fecha){return ResponseEntity.ok(service.byFecha(fecha));} @PostMapping public ResponseEntity<Cita> create(@Valid @RequestBody CitaRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(r));} @PutMapping("/{id}") public ResponseEntity<Cita> update(@PathVariable Long id,@Valid @RequestBody CitaRequest r){return ResponseEntity.ok(service.update(id,r));} @DeleteMapping("/{id}") public ResponseEntity<Void> delete(@PathVariable Long id){service.delete(id);return ResponseEntity.noContent().build();}}
